#https://leetcode.com/problems/word-ladder/description/
class Solution:   
    def ladderLength(self, beginWord: str, endWord: str, wordList: list[str]) -> int:
        if endWord not in wordList:
            return 0
        n = len(beginWord)

        #define function inline so no need to pass closure 'self'
        def calculateDist (w1, w2):
            result = 0
            for i in range (n):
                if w1[i] != w2[i]:
                    result += 1
            return result
        
        #store level of node along with node value
        queue = [(beginWord,1)]
        visited = {}
        visited[beginWord] = 1
        while queue != []:
            #tuple deconstruction
            (x, level) = queue.pop(0)
            
            for w in wordList:
                if w not in visited:
                    d = calculateDist(w, x)
                    if d == 1:
                        if w == endWord:
                            return level+1
                        queue.append((w, level+1))
                        visited[w] = 1
        
        return 0
    
#test cases
s = Solution()
assert s.ladderLength("a", "b", ["q", "r", "b"]) == 2
assert s.ladderLength("ab", "cd", ["ad", "cb", "ad", "cd"]) == 3
assert s.ladderLength("hit", "cog", ["hot","dot","dog","lot","log"]) == 0
assert s.ladderLength("hit", "cog", ["hot","dot","dog","lot","log","cog"]) == 5
